/* ---------------------------------------------------------------
   SPINNING TECH ORBIT — the signature element
----------------------------------------------------------------*/
function TechOrbit() {
  const containerRef = useRef(null);
  const [radius, setRadius] = useState(120);

  useEffect(() => {
    function update() {
      if (containerRef.current) {
        setRadius(containerRef.current.offsetWidth / 2 - 26);
      }
    }
    update();
    window.addEventListener("resize", update);
    return () => window.removeEventListener("resize", update);
  }, []);

  return (
    <div
      ref={containerRef}
      className="relative mx-auto aspect-square w-64 sm:w-80 md:w-96"
    >
      <div className="absolute inset-0 rounded-full border border-dashed border-zinc-700" />
      <div className="absolute inset-6 rounded-full border border-zinc-800" />

      {/* center photo */}
      <div className="absolute inset-0 z-20 flex items-center justify-center">
        <div className="float-soft h-28 w-28 overflow-hidden rounded-full ring-4 ring-lime-400 ring-opacity-40 sm:h-36 sm:w-36 md:h-44 md:w-44">
          <img
            src={PHOTO_SRC}
            alt="Nahid Hossain"
            className="h-full w-full object-cover"
          />
        </div>
      </div>

      {/* orbiting icons */}
      <div className="orbit-ring absolute inset-0 z-10">
        {ORBIT_TOOLS.map((t, i) => {
          const angle = (360 / ORBIT_TOOLS.length) * i;
          const Icon = t.icon;
          return (
            <div
              key={t.label}
              className="absolute left-1/2 top-1/2 -ml-5 -mt-5 h-10 w-10 sm:-ml-6 sm:-mt-6 sm:h-12 sm:w-12"
              style={{ transform: `rotate(${angle}deg) translate(${radius}px)` }}
            >
              <div className="orbit-counter flex h-full w-full items-center justify-center rounded-full border border-lime-400 border-opacity-30 bg-zinc-900 bg-opacity-90 shadow-lg">
                <Icon className="h-4 w-4 text-lime-300 sm:h-5 sm:w-5" strokeWidth={1.75} />
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ---------------------------------------------------------------
   NAVBAR
----------------------------------------------------------------*/
function Navbar() {
  const [open, setOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    function onScroll() {
      setScrolled(window.scrollY > 10);
    }
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  function go(id) {
    setOpen(false);
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  }

  return (
    <header
      className={`fixed inset-x-0 top-0 z-50 transition-colors duration-300 ${
        scrolled ? "bg-zinc-950 bg-opacity-90 border-b border-zinc-800" : "bg-transparent"
      }`}
    >
      <div className="mx-auto flex max-w-6xl items-center justify-between px-5 py-4 sm:px-8">
        <button onClick={() => go("home")} className="font-display text-lg font-semibold tracking-tight text-white">
          <span className="text-lime-400">&lt;/&gt;</span> nahid<span className="text-lime-400">.dev</span>
        </button>

        <nav className="hidden items-center gap-8 md:flex">
          {NAV.map((n) => (
            <button
              key={n.id}
              onClick={() => go(n.id)}
              className="text-sm font-medium text-zinc-300 transition-colors hover:text-lime-400"
            >
              {n.label}
            </button>
          ))}
        </nav>

        <button
          onClick={() => go("contact")}
          className="hidden rounded-full bg-lime-400 px-5 py-2 text-sm font-semibold text-zinc-950 transition-transform duration-200 hover:-translate-y-0.5 hover:bg-lime-300 md:inline-flex"
        >
          Hire Me
        </button>

        <button
          className="text-zinc-200 md:hidden"
          onClick={() => setOpen((v) => !v)}
          aria-label="Toggle menu"
        >
          {open ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
        </button>
      </div>

      {open && (
        <div className="border-t border-zinc-800 bg-zinc-950 px-5 pb-6 pt-2 md:hidden">
          {NAV.map((n) => (
            <button
              key={n.id}
              onClick={() => go(n.id)}
              className="block w-full py-3 text-left text-sm font-medium text-zinc-300 hover:text-lime-400"
            >
              {n.label}
            </button>
          ))}
          <button
            onClick={() => go("contact")}
            className="mt-2 w-full rounded-full bg-lime-400 px-5 py-2.5 text-sm font-semibold text-zinc-950"
          >
            Hire Me
          </button>
        </div>
      )}
    </header>
  );
}

